const input = $input.first().json;
const workflowName = String(input.workflowName || 'Scheduled Job');
const cronExpression = String(input.cronExpression || '0 9 * * *');
const message = String(input.message || 'Scheduled run from NodeBot.');

const safeName = workflowName.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeCron = cronExpression.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const safeMessage = message.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const slug = workflowName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'scheduled-job';

const sdkCode = `import { workflow, node, trigger, expr } from "@n8n/workflow-sdk";

const scheduleTrigger = trigger({
  type: "n8n-nodes-base.scheduleTrigger",
  version: 1.2,
  config: {
    name: "Schedule",
    parameters: {
      rule: {
        interval: [
          { field: "cronExpression", expression: "${safeCron}" },
        ],
      },
    },
  },
});

const logRun = node({
  type: "n8n-nodes-base.set",
  version: 3.4,
  config: {
    name: "Log Run",
    parameters: {
      mode: "manual",
      assignments: {
        assignments: [
          { id: "message", name: "message", value: "${safeMessage}", type: "string" },
          { id: "ranAt", name: "ranAt", value: expr("{{ $now.toISO() }}"), type: "string" },
        ],
      },
    },
  },
});

export default workflow("${slug}", "${safeName}")
  .add(scheduleTrigger)
  .to(logRun);`;

return [{
  json: {
    workflowName,
    cronExpression,
    message,
    sdkCode,
    validateRpc: { jsonrpc: '2.0', id: 1, method: 'tools/call', params: { name: 'validate_workflow', arguments: { code: sdkCode } } },
    createRpc: { jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: 'create_workflow_from_code', arguments: { code: sdkCode, name: workflowName, description: `Scheduled workflow running on cron: ${cronExpression}` } } },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/\r?\n/).find((l) => l.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP validate response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const t = payload.result?.content?.[0]?.text;
  return t ? JSON.parse(t) : (payload.result?.structuredContent || {});
}
const v = parseMcpSse($input.first().json.body ?? $input.first().json.data ?? '');
if (!v.valid) throw new Error('Workflow validation failed: ' + JSON.stringify(v));
const built = $('Build SDK Payload').first().json;
return [{ json: { ...built, validation: v } }];

