}
const created = parseMcpSse($input.first().json.body ?? $input.first().json.data ?? '');
const built = $('Build SDK Payload').first().json;
return [{
  json: {
    success: true,
    workflowId: created.workflowId,
    name: created.name,
    url: created.url,
    nodeCount: created.nodeCount,
    cronExpression: built.cronExpression,
    response: `Created scheduled workflow "${created.name}" (cron: ${built.cronExpression}). Open ${created.url} and activate it to start running on schedule.`,
  },
}];
